import java.util.LinkedList;public class UC4OrderedConsistLinkedList {    public static void main(String[] args) {        System.out.println("=== Train Consist Management App ===");        System.out.println("UC4: Maintain Ordered Bogie IDs (LinkedList)");        LinkedList<String> consist = new LinkedList<>();        consist.add("Engine");        consist.add("Sleeper");        consist.add("AC");        consist.add("Cargo");        consist.add("Guard");        System.out.println("Initial consist: " + consist);        consist.add(2, "Pantry Car");        System.out.println("After inserting Pantry Car at index 2: " + consist);        String removedFirst = consist.removeFirst();        String removedLast = consist.removeLast();        System.out.println("Removed first bogie: " + removedFirst);        System.out.println("Removed last bogie: " + removedLast);        System.out.println("Final ordered consist: " + consist);    }}